-- Generated from the canonical Codex corpus.
-- Upserts the 59 reviewed public documents and adds machine-readable provenance.
alter table public.codex_documents
  add column if not exists path text,
  add column if not exists category text,
  add column if not exists parent_id uuid,
  add column if not exists "order" integer default 0,
  add column if not exists provenance_status text[],
  add column if not exists evidence_basis text,
  add column if not exists last_reviewed date,
  add column if not exists is_read_only boolean default true;

create unique index if not exists codex_documents_path_unique
  on public.codex_documents(path);

create index if not exists codex_documents_parent_id_idx
  on public.codex_documents(parent_id);

do $migration$
declare
  canonical_documents jsonb := '[{"path":"/codex","title":"Codex","content":"# Codex\n\n**Evidence status:** CANONICAL DESIGN\n**Evidence basis:** User-confirmed product definition plus this repository structure.\n**Last reviewed:** 2026-07-14\n\nCodex is the map of Eddie''s personal cognitive operating system and connected creative work.\n\n## Product boundary\n\n- **Legacy Codex:** the personal cognitive operating system. It answers what matters now, what should happen next, and what context must not be lost.\n- **Foundry Console:** the builder and operations environment for tools, agents, integrations, and deployments.\n- **This site:** a documentation and architecture viewer. It does not prove that every system shown is deployed or automated.\n\n## Truth rule\n\nFacts, active software, plans, and unimplemented concepts are labeled separately. A blank or unknown value is preferable to an invented one.\n","category":"root","parent_path":null,"document_order":0,"is_read_only":true,"provenance_status":["repository_evidence","concept","unknown"],"evidence_basis":"User-confirmed product definition plus this repository structure.","last_reviewed":"2026-07-14"},{"path":"/codex/root","title":"Root","content":"# Root\n\n**Evidence status:** CANONICAL DESIGN\n**Evidence basis:** User-confirmed identity and operating preferences.\n**Last reviewed:** 2026-07-14\n\nThe Root territory holds identity, working style, and the Reality Filter.\n\nIt is not an analytics engine. It contains durable context that should guide decisions across photography, software, business, and personal systems.\n","category":"root","parent_path":"/codex","document_order":0,"is_read_only":true,"provenance_status":["concept"],"evidence_basis":"User-confirmed identity and operating preferences.","last_reviewed":"2026-07-14"},{"path":"/codex/root/identity.md","title":"Identity","content":"# Identity\n\n**Evidence status:** VERIFIED FACTS\n**Evidence basis:** User profile and user-confirmed professional history.\n**Last reviewed:** 2026-07-14\n\nEdward Emory Photography is a professional photographer, timelapse filmmaker, teacher, and self-taught AI/software builder.\n\n## Creative practice\n\n- Primary specialties: astrophotography, landscape photography, long exposure, low light, and 4K timelapse.\n- Secondary work: wildlife, portrait and event photography, and drone aerials.\n- Artistic themes: awe, childlike wonder, alive silence, cosmic perspective, and the message “you are enough.”\n- Business website: https://www.edwardemory.com\n\nPrivate employment, home-location, and legal-identity details are intentionally excluded from this public viewer.\n","category":"root","parent_path":"/codex/root","document_order":0,"is_read_only":true,"provenance_status":["verified"],"evidence_basis":"User profile and user-confirmed professional history.","last_reviewed":"2026-07-14"},{"path":"/codex/root/territory_mode.md","title":"Territory Mode","content":"# Territory Mode\n\n**Evidence status:** CANONICAL DESIGN\n**Evidence basis:** User-confirmed interaction needs and development rules.\n**Last reviewed:** 2026-07-14\n\nTerritory Mode is a working metaphor for protecting attention and moving one real outcome forward at a time.\n\n## Operating rules\n\n1. Start from the vivid end-state, then reverse-engineer the next actions.\n2. Ask one important question at a time when input is required.\n3. Prefer a single command or one-click path over long copy-and-paste chains.\n4. Preserve unfinished work and avoid unrelated changes.\n5. Convert important decisions into durable files or canonical records.\n6. Verify before claiming completion.\n\nThere is no verified automated “territory engine” measuring hours, interruptions, or energy.\n","category":"root","parent_path":"/codex/root","document_order":1,"is_read_only":true,"provenance_status":["concept"],"evidence_basis":"User-confirmed interaction needs and development rules.","last_reviewed":"2026-07-14"},{"path":"/codex/root/reality_filter.md","title":"Reality Filter","content":"# Reality Filter\n\n**Evidence status:** CANONICAL DESIGN\n**Evidence basis:** User-authored reality-filter rules and current correction requirements.\n**Last reviewed:** 2026-07-14\n\nThe Reality Filter prevents ideas, generated prose, and guesses from being presented as facts.\n\n## Required labels\n\n- **Verified:** supported by a user-confirmed statement, observable repository state, or connected system evidence.\n- **Partial:** related evidence exists, but the full claim is not established.\n- **Inference:** a conclusion drawn from evidence and clearly labeled as such.\n- **Unknown:** not yet verified.\n- **Concept:** desired behavior or design, not current functionality.\n\n## Non-negotiable rule\n\nNo invented equipment, finances, health metrics, integrations, customers, bookings, project completion, or performance results.\n","category":"root","parent_path":"/codex/root","document_order":2,"is_read_only":true,"provenance_status":["concept","unknown"],"evidence_basis":"User-authored reality-filter rules and current correction requirements.","last_reviewed":"2026-07-14"},{"path":"/codex/council","title":"Council","content":"# Council\n\n**Evidence status:** UNVERIFIED CONCEPT — NOT IMPLEMENTED\n**Evidence basis:** Role names exist in the Codex information architecture; no autonomous council runtime is verified.\n**Last reviewed:** 2026-07-14\n\nCouncil is a set of decision-making lenses, not a verified staff, board, or continuously running group of agents.\n\nEddie remains the owner and final decision-maker. The role pages are prompts for reviewing work from different perspectives.\n","category":"council","parent_path":"/codex","document_order":1,"is_read_only":true,"provenance_status":["concept","unknown"],"evidence_basis":"Role names exist in the Codex information architecture; no autonomous council runtime is verified.","last_reviewed":"2026-07-14"},{"path":"/codex/council/roles","title":"Council Roles","content":"# Council Roles\n\n**Evidence status:** UNVERIFIED CONCEPT — NOT IMPLEMENTED\n**Evidence basis:** Conceptual role taxonomy in this repository.\n**Last reviewed:** 2026-07-14\n\nThe council roles are review perspectives:\n\n- product architecture\n- technical systems\n- user experience and accessibility\n- data and AI integrity\n- creative direction\n- owner approval\n\nThey must not be interpreted as named employees, deployed agents, or delegated authority.\n","category":"council","parent_path":"/codex/council","document_order":0,"is_read_only":true,"provenance_status":["repository_evidence","concept","unknown"],"evidence_basis":"Conceptual role taxonomy in this repository.","last_reviewed":"2026-07-14"},{"path":"/codex/council/roles/architect.md","title":"Product Architect Lens","content":"# Product Architect Lens\n\n**Evidence status:** CANONICAL DESIGN\n**Evidence basis:** Legacy Codex and Foundry Console product boundary confirmed by the user.\n**Last reviewed:** 2026-07-14\n\nUse this lens to keep product boundaries clear.\n\n## Current canonical decision\n\nLegacy Codex serves the individual creator/operator. Foundry Console serves the builder/operator managing systems and deployments. They may exchange requests and status, but should not duplicate each other''s primary interface.\n","category":"council","parent_path":"/codex/council/roles","document_order":0,"is_read_only":true,"provenance_status":["concept"],"evidence_basis":"Legacy Codex and Foundry Console product boundary confirmed by the user.","last_reviewed":"2026-07-14"},{"path":"/codex/council/roles/systems_architect.md","title":"Systems Architect Lens","content":"# Systems Architect Lens\n\n**Evidence status:** CANONICAL DESIGN\n**Evidence basis:** Repository and deployment working rules.\n**Last reviewed:** 2026-07-14\n\nUse this lens to inspect repositories, data sources, deployments, auth boundaries, and failure modes.\n\n## Current known systems\n\n- GitHub repositories include codex-system-architecture, legacy-codex, and Artful-Intelligence.\n- Vercel hosts multiple projects, including this architecture viewer and Foundry Console-related work.\n- Supabase is used by this site for document storage and by other projects for application data.\n\nThe existence of a repository or project does not prove a feature is live.\n","category":"council","parent_path":"/codex/council/roles","document_order":1,"is_read_only":true,"provenance_status":["repository_evidence","concept"],"evidence_basis":"Repository and deployment working rules.","last_reviewed":"2026-07-14"},{"path":"/codex/council/roles/ux_specialist.md","title":"UX and Accessibility Lens","content":"# UX and Accessibility Lens\n\n**Evidence status:** VERIFIED FACTS\n**Evidence basis:** User-confirmed accessibility and interaction preferences.\n**Last reviewed:** 2026-07-14\n\nUse this lens to reduce friction for a highly visual, technically capable user who benefits from lower cognitive load and does not have a traditional coding background.\n\n## Requirements\n\n- Lead with the outcome.\n- Use actionable links when external setup is required.\n- Prefer one question at a time.\n- Avoid long terminal ping-pong.\n- Make iPhone-first experiences genuinely usable.\n- Use visual artifacts for decisions when prose becomes dense.\n- Explain GitHub and deployment terms in plain language.\n","category":"council","parent_path":"/codex/council/roles","document_order":2,"is_read_only":true,"provenance_status":["verified"],"evidence_basis":"User-confirmed accessibility and interaction preferences.","last_reviewed":"2026-07-14"},{"path":"/codex/council/roles/cdaao.md","title":"Data and AI Integrity Lens","content":"# Data and AI Integrity Lens\n\n**Evidence status:** CANONICAL DESIGN\n**Evidence basis:** Reality Filter and user-confirmed data-handling rules.\n**Last reviewed:** 2026-07-14\n\nUse this lens to prevent unsupported data and unsafe automation.\n\n## Responsibilities\n\n- Require provenance for personal data.\n- Separate training concepts from measured outcomes.\n- Never manufacture business, health, engagement, or model-performance metrics.\n- Keep private financial details out of public pages.\n- Treat external system state as current only after inspecting it.\n","category":"council","parent_path":"/codex/council/roles","document_order":3,"is_read_only":true,"provenance_status":["concept"],"evidence_basis":"Reality Filter and user-confirmed data-handling rules.","last_reviewed":"2026-07-14"},{"path":"/codex/council/roles/creative_agent.md","title":"Creative Direction Lens","content":"# Creative Direction Lens\n\n**Evidence status:** VERIFIED FACTS\n**Evidence basis:** User-confirmed artistic themes and photography practice.\n**Last reviewed:** 2026-07-14\n\nUse this lens to preserve Eddie''s visual identity: awe, scale, cosmic perspective, natural wonder, and emotionally honest processing.\n\nAI may help organize, analyze, teach, or prototype. It must not replace the authorship of Eddie''s photographs or invent a body of work he did not make.\n","category":"council","parent_path":"/codex/council/roles","document_order":4,"is_read_only":true,"provenance_status":["verified"],"evidence_basis":"User-confirmed artistic themes and photography practice.","last_reviewed":"2026-07-14"},{"path":"/codex/council/roles/chairman.md","title":"Owner and Final Decision Maker","content":"# Owner and Final Decision Maker\n\n**Evidence status:** VERIFIED FACTS\n**Evidence basis:** User ownership of the projects and explicit approval rules.\n**Last reviewed:** 2026-07-14\n\nEddie is the owner and final decision-maker.\n\nAgents may inspect, recommend, implement requested work, and verify it. Structural changes, deletions, schema redesigns, and materially different product directions require clear authorization.\n","category":"council","parent_path":"/codex/council/roles","document_order":5,"is_read_only":true,"provenance_status":["verified"],"evidence_basis":"User ownership of the projects and explicit approval rules.","last_reviewed":"2026-07-14"},{"path":"/codex/council/protocols","title":"Protocols","content":"# Protocols\n\n**Evidence status:** CANONICAL DESIGN\n**Evidence basis:** User-confirmed agent behavior and Reality Filter.\n**Last reviewed:** 2026-07-14\n\nProtocols are working rules for reliable collaboration. They are not evidence of an autonomous orchestration service.\n\nThe active core is: inspect reality, define the outcome, make the smallest safe change, verify it, and record what changed.\n","category":"council","parent_path":"/codex/council","document_order":1,"is_read_only":true,"provenance_status":["concept"],"evidence_basis":"User-confirmed agent behavior and Reality Filter.","last_reviewed":"2026-07-14"},{"path":"/codex/council/protocols/7_phase_protocol.md","title":"Seven-Phase Work Protocol","content":"# Seven-Phase Work Protocol\n\n**Evidence status:** CANONICAL DESIGN\n**Evidence basis:** Consolidation of the user-confirmed plan, execute, verify, and durability rules.\n**Last reviewed:** 2026-07-14\n\n1. **Orient:** identify the real repository, page, data source, and current state.\n2. **Verify:** classify claims as verified, partial, inferred, unknown, or concept.\n3. **Define:** state the intended outcome and constraints.\n4. **Plan:** break work into testable steps.\n5. **Execute:** make scoped changes while preserving unrelated work.\n6. **Validate:** test the original failure, the build, and the live result.\n7. **Record:** save decisions, links, migrations, and remaining risks.\n\nThis is a collaboration protocol, not proof that a seven-stage software engine is deployed.\n","category":"council","parent_path":"/codex/council/protocols","document_order":0,"is_read_only":true,"provenance_status":["concept","unknown"],"evidence_basis":"Consolidation of the user-confirmed plan, execute, verify, and durability rules.","last_reviewed":"2026-07-14"},{"path":"/codex/council/protocols/swarm_layer.md","title":"Parallel Agent Work","content":"# Parallel Agent Work\n\n**Evidence status:** MIXED — FACTS AND UNIMPLEMENTED DESIGN\n**Evidence basis:** Cloud coding agents are used; no persistent swarm service is verified.\n**Last reviewed:** 2026-07-14\n\nParallel agents can be useful when tasks are independent, such as repository inspection, test analysis, and documentation review.\n\n## Current reality\n\n- Eddie uses cloud-based coding agents and connected tools.\n- Agent work must be reconciled against the shared repository before acceptance.\n- No always-on swarm scheduler, shared autonomous memory, or self-governing agent hierarchy is verified.\n","category":"council","parent_path":"/codex/council/protocols","document_order":1,"is_read_only":true,"provenance_status":["verified","concept"],"evidence_basis":"Cloud coding agents are used; no persistent swarm service is verified.","last_reviewed":"2026-07-14"},{"path":"/codex/council/protocols/transparent_reasoning.md","title":"Transparent Work Reporting","content":"# Transparent Work Reporting\n\n**Evidence status:** CANONICAL DESIGN\n**Evidence basis:** User-confirmed transparency and failure-handling rules.\n**Last reviewed:** 2026-07-14\n\nReports should expose assumptions, evidence, actions, and verification without pretending inaccessible internal reasoning is available.\n\n## Required behavior\n\n- Explain tool failures briefly and try one safe alternate path.\n- Read back identifiers before high-impact actions.\n- Tag uncertain claims.\n- Provide the command or link that lets Eddie verify the result.\n- Never claim a deploy, migration, merge, or security boundary succeeded without direct evidence.\n","category":"council","parent_path":"/codex/council/protocols","document_order":2,"is_read_only":true,"provenance_status":["concept"],"evidence_basis":"User-confirmed transparency and failure-handling rules.","last_reviewed":"2026-07-14"},{"path":"/codex/territory","title":"Territory","content":"# Territory\n\n**Evidence status:** CANONICAL DESIGN\n**Evidence basis:** Codex information architecture and repository workflow.\n**Last reviewed:** 2026-07-14\n\nTerritory is the governance layer for deciding which record is canonical and how changes move from idea to verified state.\n\nNo geographic territory, ownership ledger, or automated governance service is implied.\n","category":"territory","parent_path":"/codex","document_order":2,"is_read_only":true,"provenance_status":["repository_evidence","concept"],"evidence_basis":"Codex information architecture and repository workflow.","last_reviewed":"2026-07-14"},{"path":"/codex/territory/territory_ledger.md","title":"Canonical Registry","content":"# Canonical Registry\n\n**Evidence status:** CANONICAL DESIGN\n**Evidence basis:** User-confirmed durability and source-of-truth rules.\n**Last reviewed:** 2026-07-14\n\n## Current source hierarchy\n\n1. Direct, current user confirmation.\n2. Live repository, deployment, database, or connected-app evidence.\n3. Canonical product definitions and decision records.\n4. Older chat summaries and planning documents.\n5. Inference, clearly labeled.\n\nConflicting records are not silently merged. The conflict is surfaced and a candidate canonical value is proposed.\n","category":"territory","parent_path":"/codex/territory","document_order":0,"is_read_only":true,"provenance_status":["concept"],"evidence_basis":"User-confirmed durability and source-of-truth rules.","last_reviewed":"2026-07-14"},{"path":"/codex/territory/boot_sequence.md","title":"Session Boot Sequence","content":"# Session Boot Sequence\n\n**Evidence status:** CANONICAL DESIGN\n**Evidence basis:** User-confirmed preference for guided, low-friction execution.\n**Last reviewed:** 2026-07-14\n\nA practical session starts with four checks:\n\n1. What outcome does Eddie want now?\n2. What is the latest observable state?\n3. What is the smallest safe next action?\n4. What evidence will prove completion?\n\nThere is no fixed 6:00 a.m. routine or biometric-triggered boot sequence verified.\n","category":"territory","parent_path":"/codex/territory","document_order":1,"is_read_only":true,"provenance_status":["concept"],"evidence_basis":"User-confirmed preference for guided, low-friction execution.","last_reviewed":"2026-07-14"},{"path":"/codex/territory/version_schema.md","title":"Version and Status Schema","content":"# Version and Status Schema\n\n**Evidence status:** CANONICAL DESIGN\n**Evidence basis:** Git workflow and Reality Filter.\n**Last reviewed:** 2026-07-14\n\n## Software state\n\n- repository\n- branch\n- commit\n- pull request\n- deployment\n- database migration\n\n## Product state\n\n- concept\n- prototype\n- blocked\n- active development\n- deployed\n- verified live\n- paused\n- retired\n\nA version number does not establish deployment. A deployed URL does not establish that its content is correct.\n","category":"territory","parent_path":"/codex/territory","document_order":2,"is_read_only":true,"provenance_status":["concept"],"evidence_basis":"Git workflow and Reality Filter.","last_reviewed":"2026-07-14"},{"path":"/codex/territory/update_protocol.md","title":"Update Protocol","content":"# Update Protocol\n\n**Evidence status:** CANONICAL DESIGN\n**Evidence basis:** Repository instructions and user-confirmed change-safety rules.\n**Last reviewed:** 2026-07-14\n\n1. Inventory the current state.\n2. Protect unrelated work.\n3. Add a regression check for the failure.\n4. Change the canonical source.\n5. Add forward-only migrations for already-applied database history.\n6. Run tests, type checks, lint, and build as applicable.\n7. Publish through a branch and pull request unless direct production action was explicitly approved.\n8. Verify the live page and record the result.\n","category":"territory","parent_path":"/codex/territory","document_order":3,"is_read_only":true,"provenance_status":["repository_evidence","concept"],"evidence_basis":"Repository instructions and user-confirmed change-safety rules.","last_reviewed":"2026-07-14"},{"path":"/codex/artistic_systems","title":"Artistic Systems","content":"# Artistic Systems\n\n**Evidence status:** VERIFIED FACTS\n**Evidence basis:** User-confirmed photography practice and Artful Intelligence work.\n**Last reviewed:** 2026-07-14\n\nThis territory covers Eddie''s real photography practice and software experiments built around creative work.\n\nIt separates owned gear and completed shoots from planned expeditions, product ideas, and prototype software.\n","category":"artistic_systems","parent_path":"/codex","document_order":3,"is_read_only":true,"provenance_status":["verified"],"evidence_basis":"User-confirmed photography practice and Artful Intelligence work.","last_reviewed":"2026-07-14"},{"path":"/codex/artistic_systems/photography_ops","title":"Photography Operations","content":"# Photography Operations\n\n**Evidence status:** VERIFIED FACTS\n**Evidence basis:** User-confirmed specialties, equipment, and field projects.\n**Last reviewed:** 2026-07-14\n\n## Primary work\n\n- astrophotography\n- landscape photography\n- timelapse filmmaking\n- night and low-light work\n- long exposure\n\n## Secondary work\n\n- wildlife\n- portraits and events\n- drone aerials\n\nEquipment and project pages list only confirmed ownership or confirmed status.\n","category":"artistic_systems","parent_path":"/codex/artistic_systems","document_order":0,"is_read_only":true,"provenance_status":["verified"],"evidence_basis":"User-confirmed specialties, equipment, and field projects.","last_reviewed":"2026-07-14"},{"path":"/codex/artistic_systems/photography_ops/astro_ops.md","title":"Astrophotography Operations","content":"# Astrophotography Operations\n\n**Evidence status:** VERIFIED FACTS\n**Evidence basis:** User-confirmed gear, baseline settings, tracker ownership, and completed shoots.\n**Last reviewed:** 2026-07-14\n\n## Baseline capture setup\n\n- Sony A7 III with Sony 20mm f/1.8 G.\n- Typical untracked Milky Way starting point: 15 seconds, ISO 4000, f/1.8 to f/2.2.\n- Final settings still depend on sky brightness, foreground, tracking, and the intended blend.\n\n## Tracker experience\n\nEddie owns a Star Adventurer Pro and Star Adventurer Mini. A confirmed example used the Star Adventurer Pro for a single 121-second exposure.\n\n## Confirmed field work\n\n- La Cumbre Peak aurora panorama, May 12, 2024: 17 handheld portrait frames with the Milky Way core, aurora, airglow, and zodiacal light.\n- Perseids at Lizard''s Mouth, 2020: 2,305 frames, 13 hours on site, and 186 hours of post-production.\n- Death Valley new-moon work at Ubehebe Crater, October 2024.\n\nNo unverified tracked-panorama or advanced blending capability is claimed.\n","category":"artistic_systems","parent_path":"/codex/artistic_systems/photography_ops","document_order":0,"is_read_only":true,"provenance_status":["verified","unknown"],"evidence_basis":"User-confirmed gear, baseline settings, tracker ownership, and completed shoots.","last_reviewed":"2026-07-14"},{"path":"/codex/artistic_systems/photography_ops/timelapse_ops.md","title":"Timelapse Operations","content":"# Timelapse Operations\n\n**Evidence status:** VERIFIED FACTS\n**Evidence basis:** User-confirmed 4K timelapse specialty and completed Perseids project.\n**Last reviewed:** 2026-07-14\n\nEddie produces 4K timelapse work and has deep experience with long-duration capture and post-production.\n\nThe strongest quantified example currently recorded is the 2020 Perseids project: 2,305 source frames, 13 hours on location, and 186 hours of post work.\n\nNo universal interval, frame count, storage requirement, or completion time is asserted; each sequence requires a shoot-specific plan.\n","category":"artistic_systems","parent_path":"/codex/artistic_systems/photography_ops","document_order":1,"is_read_only":true,"provenance_status":["verified"],"evidence_basis":"User-confirmed 4K timelapse specialty and completed Perseids project.","last_reviewed":"2026-07-14"},{"path":"/codex/artistic_systems/photography_ops/landscapes.md","title":"Landscape Operations","content":"# Landscape Operations\n\n**Evidence status:** VERIFIED FACTS\n**Evidence basis:** User-confirmed specialties, locations, and artistic themes.\n**Last reviewed:** 2026-07-14\n\nLandscape work is closely tied to astronomy, weather, remote places, and the feeling of scale.\n\n## Confirmed examples\n\n- La Cumbre Peak aurora and Milky Way panorama.\n- Ubehebe Crater in Death Valley during extreme heat in October 2024.\n- Lunar eclipse work on California''s Central Coast.\n- Light-painting work at Far de Favàritx in Menorca with Eric Paré and Kim Henry.\n\nProcessing ranges from natural scene fidelity to clearly disclosed creative composites.\n","category":"artistic_systems","parent_path":"/codex/artistic_systems/photography_ops","document_order":2,"is_read_only":true,"provenance_status":["verified"],"evidence_basis":"User-confirmed specialties, locations, and artistic themes.","last_reviewed":"2026-07-14"},{"path":"/codex/artistic_systems/photography_ops/gear_specs.md","title":"Verified Gear Inventory","content":"# Verified Gear Inventory\n\n**Evidence status:** VERIFIED FACTS\n**Evidence basis:** Equipment ownership directly confirmed by the user.\n**Last reviewed:** 2026-07-14\n\n## Camera bodies\n\n| Camera | Confirmed role |\n| --- | --- |\n| Sony A7 III | Primary full-frame camera for astrophotography, landscapes, timelapse, low light, portraits, and events |\n| Sony RX10 IV | Second camera with built-in 24–600mm-equivalent zoom for wildlife, travel, and distant subjects |\n\n## Lenses owned for the Sony A7 III\n\n| Lens | Confirmed use |\n| --- | --- |\n| Sony 20mm f/1.8 G | Favorite lens; primary astrophotography and wide landscape lens |\n| Rokinon 14mm f/2.8 | Ultra-wide astrophotography and landscape lens |\n| Sony 24–70mm f/4 Zeiss Vario-Tessar | General-purpose standard zoom |\n\n## Tracking equipment\n\n- Star Adventurer Pro\n- Star Adventurer Mini\n\n## Other equipment\n\nTripod, head, filter, battery, memory-card, drone-model, and maintenance details are **Unknown — not yet verified for this public inventory**.\n\nEquipment researched or considered for purchase is not listed as owned.\n","category":"artistic_systems","parent_path":"/codex/artistic_systems/photography_ops","document_order":3,"is_read_only":true,"provenance_status":["verified","unknown"],"evidence_basis":"Equipment ownership directly confirmed by the user.","last_reviewed":"2026-07-14"},{"path":"/codex/artistic_systems/photography_ops/firefall_2026.md","title":"Firefall Status","content":"# Firefall Status\n\n**Evidence status:** UNVERIFIED CONCEPT — NOT IMPLEMENTED\n**Evidence basis:** No user-confirmed Firefall trip, booking, dates, permit, or equipment plan was located in the available context.\n**Last reviewed:** 2026-07-14\n\nA prior corpus presented a detailed Yosemite Firefall trip as if it were scheduled. That status was unsupported.\n\n## Current status\n\n- Trip: **Unknown — not confirmed**\n- Dates: **Unknown — not confirmed**\n- Lodging or campsite: **Unknown — not confirmed**\n- Permit or reservation: **Unknown — not confirmed**\n- Shot plan: **Not approved**\n\nIf Firefall becomes a real project, this page should be rebuilt from confirmed reservations, current park rules, weather, water flow, and Eddie''s actual gear.\n","category":"artistic_systems","parent_path":"/codex/artistic_systems/photography_ops","document_order":4,"is_read_only":true,"provenance_status":["concept","unknown"],"evidence_basis":"No user-confirmed Firefall trip, booking, dates, permit, or equipment plan was located in the available context.","last_reviewed":"2026-07-14"},{"path":"/codex/artistic_systems/photography_ops/namibia_2026.md","title":"Namibia Workshop Status","content":"# Namibia Workshop Status\n\n**Evidence status:** VERIFIED PROJECT STATUS\n**Evidence basis:** User-confirmed workshop history and June 2026 relaunch update.\n**Last reviewed:** 2026-07-14\n\nThe Namibia workshop has been attempted and revised across multiple years, but no current departure is booked or on sale.\n\n## Confirmed history\n\n- Partner and local guide: Richard Morsbach of Namib Adventure.\n- Earlier 2023 versions were proposed and later postponed.\n- Prior launches produced only one or two signups and did not become a completed workshop.\n- The newer concept is a 7-night/8-day slack-packing format combining a four-day hut-to-hut section with lodge-based editing and wildlife work.\n\n## Current status\n\n- Candidate year: **2027 or 2028**, depending on logistics and build quality.\n- Exact dates: **Unknown — not confirmed**\n- Final route: **Unknown — not confirmed**\n- Final price: **Unknown — not confirmed**\n- Booked participants: **None confirmed in the available record**\n- Public sales page readiness: **Not verified**\n\nHistorical itineraries and prices are references only, not current commitments.\n","category":"artistic_systems","parent_path":"/codex/artistic_systems/photography_ops","document_order":5,"is_read_only":true,"provenance_status":["verified","unknown"],"evidence_basis":"User-confirmed workshop history and June 2026 relaunch update.","last_reviewed":"2026-07-14"},{"path":"/codex/artistic_systems/artful_intelligence","title":"Artful Intelligence","content":"# Artful Intelligence\n\n**Evidence status:** MIXED — FACTS AND UNIMPLEMENTED DESIGN\n**Evidence basis:** User-confirmed platform vision plus shipped and prototype project history.\n**Last reviewed:** 2026-07-14\n\nArtful Intelligence is Eddie''s umbrella concept for helping creatives automate tedious work and return to creating.\n\n## Confirmed audience\n\nPhotographers, artists, writers, musicians, and other creative professionals.\n\n## Confirmed shipped work\n\nPhotographer Agent Pack V1 launched in June 2026 with a Vercel storefront and Gumroad listing.\n\n## Important boundary\n\nThe broader all-in-one platform is not verified as a completed product. Individual prototypes and products must be evaluated separately.\n","category":"artistic_systems","parent_path":"/codex/artistic_systems","document_order":1,"is_read_only":true,"provenance_status":["verified","concept","unknown"],"evidence_basis":"User-confirmed platform vision plus shipped and prototype project history.","last_reviewed":"2026-07-14"},{"path":"/codex/artistic_systems/artful_intelligence/ai_overview.md","title":"Artful Intelligence Product Overview","content":"# Artful Intelligence Product Overview\n\n**Evidence status:** MIXED — FACTS AND UNIMPLEMENTED DESIGN\n**Evidence basis:** User-confirmed vision and project launch record.\n**Last reviewed:** 2026-07-14\n\n## Vision\n\nA creator-focused system that can support planning, photography education, client workflow, product sales, and automation without burying the creative user in technical setup.\n\n## Reality as of review\n\n- Photographer Agent Pack V1: shipped.\n- Artful Intelligence storefront: deployed.\n- Photo Coach: prototype/MVP work exists; production availability is not verified.\n- Creator-wide operating system: concept, not a verified complete platform.\n- Native iOS product: multiple concepts exist; no single App Store release is verified.\n","category":"artistic_systems","parent_path":"/codex/artistic_systems/artful_intelligence","document_order":0,"is_read_only":true,"provenance_status":["verified","concept","unknown"],"evidence_basis":"User-confirmed vision and project launch record.","last_reviewed":"2026-07-14"},{"path":"/codex/artistic_systems/artful_intelligence/photo_coach_mvp.md","title":"Photo Coach MVP","content":"# Photo Coach MVP\n\n**Evidence status:** VERIFIED PROJECT STATUS\n**Evidence basis:** User-confirmed May and August 2025 MVP work.\n**Last reviewed:** 2026-07-14\n\nPhoto Coach is an AI-assisted critique and education concept tuned for Eddie''s Sony A7 III workflow and specialties.\n\n## Confirmed build history\n\n- A FastAPI backend was designed to use OpenAI vision responses with structured JSON.\n- EXIF extraction and a mobile single-page interface were part of the MVP.\n- The intended focus is actionable feedback for astro, landscape, timelapse, and workshop scenarios.\n\n## Current unknowns\n\n- Public production URL: **Unknown — not verified**\n- Active users: **Unknown — not verified**\n- Paid customers: **Unknown — not verified**\n- Model accuracy or satisfaction metrics: **Unknown — not measured here**\n","category":"artistic_systems","parent_path":"/codex/artistic_systems/artful_intelligence","document_order":1,"is_read_only":true,"provenance_status":["verified","unknown"],"evidence_basis":"User-confirmed May and August 2025 MVP work.","last_reviewed":"2026-07-14"},{"path":"/codex/artistic_systems/artful_intelligence/edition_manager.md","title":"Edition Manager","content":"# Edition Manager\n\n**Evidence status:** MIXED — FACTS AND UNIMPLEMENTED DESIGN\n**Evidence basis:** Observable scripts, API routes, migrations, and event files in this repository.\n**Last reviewed:** 2026-07-14\n\nThis repository contains Edition Manager code, including an ingest API, migration-related tooling, local scripts, and event records.\n\n## What that proves\n\nThe implementation has source code and database design work.\n\n## What it does not prove\n\n- that every database migration is applied\n- that ingestion is running continuously\n- that print orders are automatically fulfilled\n- that inventory or sales counts are current\n- that the system has processed real customer orders\n\nRuntime status must be checked directly before any of those claims are made.\n","category":"artistic_systems","parent_path":"/codex/artistic_systems/artful_intelligence","document_order":2,"is_read_only":true,"provenance_status":["verified","repository_evidence","concept"],"evidence_basis":"Observable scripts, API routes, migrations, and event files in this repository.","last_reviewed":"2026-07-14"},{"path":"/codex/artistic_systems/artful_intelligence/6_figure_print_engine.md","title":"Print Revenue Engine","content":"# Print Revenue Engine\n\n**Evidence status:** MIXED — FACTS AND UNIMPLEMENTED DESIGN\n**Evidence basis:** User-confirmed print model and product goals; no six-figure performance evidence.\n**Last reviewed:** 2026-07-14\n\nEddie''s fine-art print model centers on one-of-one archival metal prints using ChromaLuxe.\n\n## Confirmed business context\n\n- One-of-one positioning is intentional.\n- Fine-art qualification and high-value collector positioning have been explored.\n- Agent C in Photographer Agent Pack V1 focuses on print-drop workflow.\n\n## Reality check\n\n“Six figure” was a goal label, not a verified revenue result. This page contains no claimed annual revenue, conversion rate, collector count, sell-through rate, or active inventory because those figures have not been verified here.\n","category":"artistic_systems","parent_path":"/codex/artistic_systems/artful_intelligence","document_order":3,"is_read_only":true,"provenance_status":["verified","concept"],"evidence_basis":"User-confirmed print model and product goals; no six-figure performance evidence.","last_reviewed":"2026-07-14"},{"path":"/codex/artistic_systems/artful_intelligence/creative_automations.md","title":"Creative Automations","content":"# Creative Automations\n\n**Evidence status:** MIXED — FACTS AND UNIMPLEMENTED DESIGN\n**Evidence basis:** User-confirmed workflow goals and connected-tool usage.\n**Last reviewed:** 2026-07-14\n\nAutomation should remove repetitive work while leaving creative judgment with Eddie.\n\n## Confirmed workflow areas\n\n- GitHub repository work\n- Vercel deployment\n- Supabase-backed applications\n- Notion documentation\n- photography business planning\n- agent-assisted product workflows\n\n## Boundary\n\nNo claim is made that lead generation, client delivery, print fulfillment, bookkeeping, social posting, or newsletter publishing is fully automated. Each workflow requires direct verification.\n","category":"artistic_systems","parent_path":"/codex/artistic_systems/artful_intelligence","document_order":4,"is_read_only":true,"provenance_status":["verified","concept"],"evidence_basis":"User-confirmed workflow goals and connected-tool usage.","last_reviewed":"2026-07-14"},{"path":"/codex/artistic_systems/artful_intelligence/pwa_iphone16.md","title":"iPhone-First PWA Work","content":"# iPhone-First PWA Work\n\n**Evidence status:** VERIFIED PROJECT STATUS\n**Evidence basis:** User-confirmed iPhone 16 Pro ownership and PWA prototype history.\n**Last reviewed:** 2026-07-14\n\nEddie uses an iPhone 16 Pro and consistently prioritizes mobile-first tools.\n\n## Confirmed concepts and prototypes\n\n- photo analysis and coaching interfaces\n- Camera Coach/AstroCapture planning ideas\n- a photographer workflow PWA\n- CelestiaDome EEG visualization\n- mobile 3D gallery work\n\nThese are separate experiments at different stages. This page does not combine them into a fictional single production app. App Store release, active users, offline reliability, and production backend status are **Unknown — not verified**.\n","category":"artistic_systems","parent_path":"/codex/artistic_systems/artful_intelligence","document_order":5,"is_read_only":true,"provenance_status":["verified","unknown"],"evidence_basis":"User-confirmed iPhone 16 Pro ownership and PWA prototype history.","last_reviewed":"2026-07-14"},{"path":"/codex/neuro","title":"Neuro and Biometric Work","content":"# Neuro and Biometric Work\n\n**Evidence status:** MIXED — FACTS AND UNIMPLEMENTED DESIGN\n**Evidence basis:** User-confirmed Muse 2 ownership and prototype history.\n**Last reviewed:** 2026-07-14\n\nThis territory covers experiments using a Muse 2 headset to explore focus, calm, stress, flow, and recovery.\n\nIt is a personal creative technology project, not a medical device, diagnostic system, or validated neuroscience product.\n","category":"neuro","parent_path":"/codex","document_order":4,"is_read_only":true,"provenance_status":["verified","concept"],"evidence_basis":"User-confirmed Muse 2 ownership and prototype history.","last_reviewed":"2026-07-14"},{"path":"/codex/neuro/muse2_eeg_pipeline.md","title":"Muse 2 EEG Pipeline","content":"# Muse 2 EEG Pipeline\n\n**Evidence status:** VERIFIED PROJECT STATUS\n**Evidence basis:** User-confirmed device, apps, pipeline components, and prototype goals.\n**Last reviewed:** 2026-07-14\n\n## Confirmed equipment and tools\n\n- Muse 2 headset\n- Mind Monitor with OSC\n- optional LSL exploration\n- Python OSC receiver and WebSocket bridge work\n- React/Three.js and SwiftUI visualization concepts\n\n## Confirmed project history\n\nNeuroMuse and CelestiaDome prototypes explored live EEG bands, visual feedback, and session summaries.\n\n## Limits\n\nNo clinical interpretation, diagnosis, validated brain-state detection, or proven flow classifier is claimed. Current end-to-end runtime status is **Unknown — not freshly verified**.\n","category":"neuro","parent_path":"/codex/neuro","document_order":0,"is_read_only":true,"provenance_status":["verified","unknown"],"evidence_basis":"User-confirmed device, apps, pipeline components, and prototype goals.","last_reviewed":"2026-07-14"},{"path":"/codex/neuro/websocket_servers.md","title":"EEG WebSocket Bridge","content":"# EEG WebSocket Bridge\n\n**Evidence status:** MIXED — FACTS AND UNIMPLEMENTED DESIGN\n**Evidence basis:** User-confirmed prototype pipeline; current server status not inspected in this repository.\n**Last reviewed:** 2026-07-14\n\nThe intended path is Mind Monitor OSC to a local bridge, then WebSocket messages to a browser or native visualizer.\n\nPrototype work exists in the project history. No always-on server URL, uptime, latency, throughput, or current deployment is verified on this page.\n","category":"neuro","parent_path":"/codex/neuro","document_order":1,"is_read_only":true,"provenance_status":["verified","repository_evidence","concept"],"evidence_basis":"User-confirmed prototype pipeline; current server status not inspected in this repository.","last_reviewed":"2026-07-14"},{"path":"/codex/neuro/adaptive_ml_models.md","title":"Adaptive Model Status","content":"# Adaptive Model Status\n\n**Evidence status:** UNVERIFIED CONCEPT — NOT IMPLEMENTED\n**Evidence basis:** Project history describes rule-based state ideas; no trained or validated adaptive model is verified.\n**Last reviewed:** 2026-07-14\n\nFocus, calm, stress, and flow labels have been explored as product concepts.\n\n## Current status\n\n- Personally labeled training dataset: **Unknown — not verified**\n- Trained production model: **Not verified**\n- Accuracy, precision, recall, or validation cohort: **Not available**\n- Clinical validity: **Not claimed**\n\nUntil real labeled sessions and an evaluation protocol exist, the system must be described as exploratory and rule-based.\n","category":"neuro","parent_path":"/codex/neuro","document_order":2,"is_read_only":true,"provenance_status":["concept","unknown"],"evidence_basis":"Project history describes rule-based state ideas; no trained or validated adaptive model is verified.","last_reviewed":"2026-07-14"},{"path":"/codex/neuro/whoop_integration.md","title":"WHOOP Integration Status","content":"# WHOOP Integration Status\n\n**Evidence status:** UNVERIFIED CONCEPT — NOT IMPLEMENTED\n**Evidence basis:** User previously used WHOOP 4.0 and discussed an integration; no current live connection is verified.\n**Last reviewed:** 2026-07-14\n\nWHOOP data was considered as a recovery and sleep context source for NeuroMuse and personal planning.\n\n## Current status\n\n- Device/account use: previously used; current active status **Unknown**\n- OAuth connection: **Not verified**\n- Automatic data import: **Not verified**\n- Recovery-based scheduling: **Not implemented as a verified production workflow**\n\nNo recovery scores or health conclusions are displayed here.\n","category":"neuro","parent_path":"/codex/neuro","document_order":3,"is_read_only":true,"provenance_status":["concept","unknown"],"evidence_basis":"User previously used WHOOP 4.0 and discussed an integration; no current live connection is verified.","last_reviewed":"2026-07-14"},{"path":"/codex/neuro/bio_geometry_engine.md","title":"Biometric Visualization Concept","content":"# Biometric Visualization Concept\n\n**Evidence status:** UNVERIFIED CONCEPT — NOT IMPLEMENTED\n**Evidence basis:** User-confirmed interest in responsive 3D EEG visualization.\n**Last reviewed:** 2026-07-14\n\nThe concept is to translate live EEG signals into an expressive visual environment such as a dome, star field, sphere, or spatial animation.\n\nCelestiaDome is the clearest named direction in the available project history. No validated “Bio Geometry Engine,” production SDK, spatial-analysis model, or measured therapeutic effect is claimed.\n","category":"neuro","parent_path":"/codex/neuro","document_order":4,"is_read_only":true,"provenance_status":["concept","unknown"],"evidence_basis":"User-confirmed interest in responsive 3D EEG visualization.","last_reviewed":"2026-07-14"},{"path":"/codex/automation","title":"Automation","content":"# Automation\n\n**Evidence status:** MIXED — FACTS AND UNIMPLEMENTED DESIGN\n**Evidence basis:** Connected development workflows and repository evidence.\n**Last reviewed:** 2026-07-14\n\nEddie uses AI agents and connected tools to reduce the friction of software development and project operations.\n\nThe current reality is a collection of agent-assisted workflows, repositories, and deployments—not a single autonomous operating system.\n","category":"automation","parent_path":"/codex","document_order":5,"is_read_only":true,"provenance_status":["verified","repository_evidence","concept"],"evidence_basis":"Connected development workflows and repository evidence.","last_reviewed":"2026-07-14"},{"path":"/codex/automation/multi_agent_orchestration.md","title":"Multi-Agent Orchestration Status","content":"# Multi-Agent Orchestration Status\n\n**Evidence status:** MIXED — FACTS AND UNIMPLEMENTED DESIGN\n**Evidence basis:** User-confirmed cloud-agent usage; no persistent orchestrator verified.\n**Last reviewed:** 2026-07-14\n\nMultiple agents can inspect different bounded parts of a task in parallel, but their output must be reviewed and reconciled.\n\n## Verified\n\n- Cloud coding agents are part of Eddie''s workflow.\n- Repositories and deployment tools can be connected to agent sessions.\n\n## Not verified\n\n- persistent cross-agent memory\n- autonomous task assignment\n- a production queue or scheduler\n- agents merging or deploying without explicit workflow authority\n","category":"automation","parent_path":"/codex/automation","document_order":0,"is_read_only":true,"provenance_status":["verified","concept","unknown"],"evidence_basis":"User-confirmed cloud-agent usage; no persistent orchestrator verified.","last_reviewed":"2026-07-14"},{"path":"/codex/automation/reliability_playbook.md","title":"Reliability Playbook","content":"# Reliability Playbook\n\n**Evidence status:** CANONICAL DESIGN\n**Evidence basis:** User-confirmed agent and tool-failure rules.\n**Last reviewed:** 2026-07-14\n\n## Working rules\n\n1. Inspect the actual system before trusting old architecture prose.\n2. Reproduce the failure and trace the data source.\n3. Make one scoped correction at a time.\n4. Use tests to prevent the false state from returning.\n5. Explain failures briefly; do not dump raw errors on Eddie.\n6. Retry a temporary failure once, then use a different safe path.\n7. Verify identifiers and captured values before writes.\n8. Never report success from intent alone.\n","category":"automation","parent_path":"/codex/automation","document_order":1,"is_read_only":true,"provenance_status":["concept"],"evidence_basis":"User-confirmed agent and tool-failure rules.","last_reviewed":"2026-07-14"},{"path":"/codex/automation/rag_photography.md","title":"Photography Retrieval Status","content":"# Photography Retrieval Status\n\n**Evidence status:** UNVERIFIED CONCEPT — NOT IMPLEMENTED\n**Evidence basis:** A prior design described RAG; no indexed production knowledge base is verified.\n**Last reviewed:** 2026-07-14\n\nA photography retrieval system could use Eddie''s camera manuals, field notes, confirmed gear, and teaching material to answer context-specific questions.\n\n## Current status\n\n- Production vector database: **Not verified**\n- Indexed manuals or note count: **Unknown**\n- Embedding model: **Not selected here**\n- Query latency, relevance, satisfaction, and accuracy: **Not measured**\n\nThe earlier counts and performance numbers were unsupported and have been removed.\n","category":"automation","parent_path":"/codex/automation","document_order":2,"is_read_only":true,"provenance_status":["concept","unknown"],"evidence_basis":"A prior design described RAG; no indexed production knowledge base is verified.","last_reviewed":"2026-07-14"},{"path":"/codex/automation/automation_pipelines.md","title":"Automation Pipeline Status","content":"# Automation Pipeline Status\n\n**Evidence status:** MIXED — FACTS AND UNIMPLEMENTED DESIGN\n**Evidence basis:** Repository, GitHub, Vercel, and Supabase evidence.\n**Last reviewed:** 2026-07-14\n\n## Verified components\n\n- GitHub repositories store application code and history.\n- Vercel projects deploy several web applications.\n- This site reads Codex documents with a Supabase-backed path and a canonical repository fallback.\n- Edition Manager-related APIs and scripts exist in this repository.\n\n## Not established by those facts\n\n- continuous operation\n- successful customer fulfillment\n- error-free synchronization\n- complete Notion or memory ingestion\n- production monitoring coverage\n\nEach pipeline needs its own live verification.\n","category":"automation","parent_path":"/codex/automation","document_order":3,"is_read_only":true,"provenance_status":["verified","repository_evidence","concept"],"evidence_basis":"Repository, GitHub, Vercel, and Supabase evidence.","last_reviewed":"2026-07-14"},{"path":"/codex/business","title":"Business","content":"# Business\n\n**Evidence status:** VERIFIED FACTS\n**Evidence basis:** User-confirmed photography business, products, and workshop history.\n**Last reviewed:** 2026-07-14\n\nEdward Emory Photography is the established creative business. Artful Intelligence is the newer product and automation direction.\n\nCurrent business work includes fine-art prints, photography services, education/workshops, and digital creator tools. Revenue or customer counts are not published without current verified records.\n","category":"business","parent_path":"/codex","document_order":6,"is_read_only":true,"provenance_status":["verified"],"evidence_basis":"User-confirmed photography business, products, and workshop history.","last_reviewed":"2026-07-14"},{"path":"/codex/business/drop_model.md","title":"Fine-Art Print Drop Model","content":"# Fine-Art Print Drop Model\n\n**Evidence status:** MIXED — FACTS AND UNIMPLEMENTED DESIGN\n**Evidence basis:** User-confirmed one-of-one metal print model and agent-pack workflow.\n**Last reviewed:** 2026-07-14\n\n## Confirmed model\n\n- one-of-one archival metal prints\n- ChromaLuxe as the named print medium\n- collector-oriented positioning\n- limited-release storytelling rather than commodity print volume\n\n## Current unknowns\n\n- active inventory\n- next drop date\n- collector list size\n- sell-through rate\n- current revenue\n\nThe Print Drop Agent is a shipped component of Photographer Agent Pack V1; that does not prove a fully automated sales operation.\n","category":"business","parent_path":"/codex/business","document_order":0,"is_read_only":true,"provenance_status":["verified","concept","unknown"],"evidence_basis":"User-confirmed one-of-one metal print model and agent-pack workflow.","last_reviewed":"2026-07-14"},{"path":"/codex/business/workshop_engines.md","title":"Workshop Business Status","content":"# Workshop Business Status\n\n**Evidence status:** VERIFIED PROJECT STATUS\n**Evidence basis:** User-confirmed Namibia attempts and current planning direction.\n**Last reviewed:** 2026-07-14\n\nEddie is a natural teacher and has pursued photography workshop products, especially Namibia.\n\n## Confirmed reality\n\n- Multiple Namibia launch attempts occurred between 2020 and 2023.\n- Those attempts produced limited signups and did not become the intended completed workshop.\n- Richard Morsbach is the named local guide/partner.\n- A redesigned 7-night/8-day format is being considered for 2027 or 2028.\n\nThere is no confirmed current workshop date, enrollment count, venue, price, profit, or launch funnel on this page.\n","category":"business","parent_path":"/codex/business","document_order":1,"is_read_only":true,"provenance_status":["verified"],"evidence_basis":"User-confirmed Namibia attempts and current planning direction.","last_reviewed":"2026-07-14"},{"path":"/codex/business/money_os.md","title":"Money OS","content":"# Money OS\n\n**Evidence status:** VERIFIED PROJECT STATUS\n**Evidence basis:** User requested financial tracking; this Vercel site is public and is not the appropriate ledger.\n**Last reviewed:** 2026-07-14\n\nPrivate financial figures are intentionally excluded from this public architecture site.\n\n## Public-safe status\n\nThis viewer intentionally contains no personal financial history, balances, obligations, income, expenses, tax information, or private business records.\n\n## Rule\n\nFinancial planning belongs in a private, access-controlled system with dated source records. No invented targets, allocations, dashboards, deductions, or tax payments are permitted here.\n","category":"business","parent_path":"/codex/business","document_order":2,"is_read_only":true,"provenance_status":["verified","repository_evidence"],"evidence_basis":"User requested financial tracking; this Vercel site is public and is not the appropriate ledger.","last_reviewed":"2026-07-14"},{"path":"/codex/personal_os","title":"Personal OS","content":"# Personal OS\n\n**Evidence status:** CANONICAL DESIGN\n**Evidence basis:** User-confirmed accessibility and work preferences.\n**Last reviewed:** 2026-07-14\n\nThe Personal OS is a practical support layer for preserving context, lowering overwhelm, and turning complex visions into one manageable next action.\n\nIt should support Eddie''s life and creativity, not turn self-understanding into another endless optimization project.\n","category":"personal_os","parent_path":"/codex","document_order":7,"is_read_only":true,"provenance_status":["concept"],"evidence_basis":"User-confirmed accessibility and work preferences.","last_reviewed":"2026-07-14"},{"path":"/codex/personal_os/personality_manual.md","title":"Working With Eddie","content":"# Working With Eddie\n\n**Evidence status:** VERIFIED FACTS\n**Evidence basis:** User-confirmed communication and execution preferences.\n**Last reviewed:** 2026-07-14\n\n## What works\n\n- Guide the conversation and ask specific questions.\n- Ask one important question at a time when possible.\n- Start with the outcome, then give concrete steps.\n- Explain unfamiliar technical terms without talking down.\n- Use direct links for tools, setup, and verification.\n- Prefer one safe command over repeated terminal copy-and-paste.\n- Make progress visible through working artifacts.\n- Be direct when an idea is not viable or evidence is missing.\n\n## What does not work\n\n- invented details\n- vague reassurance\n- long unprioritized lists\n- claiming access or completion that was not verified\n- treating plans as shipped products\n","category":"personal_os","parent_path":"/codex/personal_os","document_order":0,"is_read_only":true,"provenance_status":["verified","unknown"],"evidence_basis":"User-confirmed communication and execution preferences.","last_reviewed":"2026-07-14"},{"path":"/codex/personal_os/neurodivergent_os.md","title":"Accessible Work System","content":"# Accessible Work System\n\n**Evidence status:** VERIFIED FACTS\n**Evidence basis:** User-confirmed interaction preferences and accessibility needs.\n**Last reviewed:** 2026-07-14\n\nEddie benefits from systems that reduce working-memory load and ambiguity.\n\n## Practical design requirements\n\n- preserve context across sessions\n- reduce decisions to the next meaningful choice\n- use visual end-states and reverse-engineered steps\n- avoid unnecessary context switching\n- make recovery and sleep legitimate constraints\n- separate urgent action from optional ideas\n- record decisions outside chat\n\nThis is an accessibility and workflow framework, not a medical treatment plan.\n","category":"personal_os","parent_path":"/codex/personal_os","document_order":1,"is_read_only":true,"provenance_status":["verified"],"evidence_basis":"User-confirmed interaction preferences and accessibility needs.","last_reviewed":"2026-07-14"},{"path":"/codex/personal_os/reflections_between_worlds.md","title":"Reflections Between Worlds","content":"# Reflections Between Worlds\n\n**Evidence status:** VERIFIED FACTS\n**Evidence basis:** User-confirmed roles, creative themes, and the tension between art and software building.\n**Last reviewed:** 2026-07-14\n\nEddie moves between several real roles: professional photographer, teacher, and AI builder.\n\nThe central tension is not lack of ideas. It is protecting enough energy and continuity to turn vivid creative visions into finished, testable work.\n\nThe recurring artistic center is awe: night skies, landscapes, time, silence, and the feeling that human life belongs inside something much larger.\n","category":"personal_os","parent_path":"/codex/personal_os","document_order":2,"is_read_only":true,"provenance_status":["verified"],"evidence_basis":"User-confirmed roles, creative themes, and the tension between art and software building.","last_reviewed":"2026-07-14"},{"path":"/codex/convergence","title":"Convergence","content":"# Convergence\n\n**Evidence status:** VERIFIED PROJECT STATUS\n**Evidence basis:** User-confirmed product differentiation and observable repository/deployment work.\n**Last reviewed:** 2026-07-14\n\nConvergence is where photography, neurotechnology experiments, personal context, business tools, and software infrastructure are evaluated together.\n\nThe goal is useful connection, not a claim that every system is already integrated.\n","category":"convergence","parent_path":"/codex","document_order":8,"is_read_only":true,"provenance_status":["verified","repository_evidence"],"evidence_basis":"User-confirmed product differentiation and observable repository/deployment work.","last_reviewed":"2026-07-14"},{"path":"/codex/convergence/convergence_log_v16.md","title":"Current Integration Status","content":"# Current Integration Status\n\n**Evidence status:** VERIFIED PROJECT STATUS\n**Evidence basis:** GitHub/Vercel inspection plus user-confirmed June–July 2026 project updates.\n**Last reviewed:** 2026-07-14\n\n## Verified progress\n\n- Legacy Codex and Foundry Console now have a defined product boundary.\n- Foundry Console received owner-only security work and Supabase-backed infrastructure in the legacy-codex project history.\n- Photographer Agent Pack V1 shipped with a Vercel storefront and Gumroad listing.\n- This codex-system-architecture app is deployed on Vercel and connected to Supabase document data.\n- The current audit identified and is replacing a large fabricated corpus in this site.\n\n## Active or incomplete\n\n- Broader Artful Intelligence platform: incomplete.\n- Photo Coach production service: not verified live.\n- Muse/EEG end-to-end runtime: not freshly verified.\n- Namibia workshop: candidate 2027 or 2028, not booked.\n- Automated creator/business operating system: not verified.\n\n## Removed claims\n\nThere is no evidence here for integrated recovery scheduling, location-focus analytics, monthly five-figure creative revenue, automatic fulfillment of customer orders, system-health percentages, or a v16.2.1 production engine.\n","category":"convergence","parent_path":"/codex/convergence","document_order":0,"is_read_only":true,"provenance_status":["verified","repository_evidence","unknown"],"evidence_basis":"GitHub/Vercel inspection plus user-confirmed June–July 2026 project updates.","last_reviewed":"2026-07-14"},{"path":"/codex/convergence/system_reflexivity.md","title":"System Reflexivity","content":"# System Reflexivity\n\n**Evidence status:** CANONICAL DESIGN\n**Evidence basis:** Reality Filter, repository audit practice, and user-confirmed real-versus-perceived progress reviews.\n**Last reviewed:** 2026-07-14\n\nSystem reflexivity means checking whether the systems are producing real outcomes or only producing more documentation.\n\n## Review loop\n\n1. **Observe:** inspect repositories, deployments, databases, and actual user results.\n2. **Compare:** separate shipped work from plans, prototypes, and repeated rebuilds.\n3. **Decide:** identify the smallest high-value correction.\n4. **Execute:** change the canonical source and its live counterpart.\n5. **Verify:** test the original problem from the user''s point of view.\n6. **Record:** preserve the evidence, decision, and remaining uncertainty.\n\nNo productivity, recovery, focus, revenue, relationship, or creative-satisfaction metric is assumed without a dated real dataset.\n","category":"convergence","parent_path":"/codex/convergence","document_order":1,"is_read_only":true,"provenance_status":["repository_evidence","concept"],"evidence_basis":"Reality Filter, repository audit practice, and user-confirmed real-versus-perceived progress reviews.","last_reviewed":"2026-07-14"}]'::jsonb;
  expected_count integer := 59;
  stored_count integer;
  changed_count integer;
begin
  insert into public.codex_documents (
    title,
    path,
    content,
    category,
    "order",
    provenance_status,
    evidence_basis,
    last_reviewed,
    is_read_only,
    updated_at
  )
  select
    canonical.title,
    canonical.path,
    canonical.content,
    canonical.category,
    canonical.document_order,
    array(select jsonb_array_elements_text(canonical.provenance_status)),
    canonical.evidence_basis,
    canonical.last_reviewed,
    canonical.is_read_only,
    now()
  from jsonb_to_recordset(canonical_documents) as canonical(
    path text,
    title text,
    content text,
    category text,
    parent_path text,
    document_order integer,
    provenance_status jsonb,
    evidence_basis text,
    last_reviewed date,
    is_read_only boolean
  )
  on conflict (path) do update
  set
    title = excluded.title,
    content = excluded.content,
    category = excluded.category,
    "order" = excluded."order",
    provenance_status = excluded.provenance_status,
    evidence_basis = excluded.evidence_basis,
    last_reviewed = excluded.last_reviewed,
    is_read_only = excluded.is_read_only,
    updated_at = now();

  get diagnostics changed_count = row_count;
  if changed_count <> expected_count then
    raise exception 'Codex reality repair rolled back: expected % upserts, applied %',
      expected_count,
      changed_count;
  end if;

  update public.codex_documents as child
  set parent_id = parent.id
  from jsonb_to_recordset(canonical_documents) as canonical(path text, parent_path text)
  left join public.codex_documents as parent on parent.path = canonical.parent_path
  where child.path = canonical.path;

  select count(*)
  into stored_count
  from public.codex_documents as document
  join jsonb_to_recordset(canonical_documents) as canonical(path text)
    on canonical.path = document.path
  where document.provenance_status is not null
    and cardinality(document.provenance_status) > 0
    and document.evidence_basis is not null
    and document.last_reviewed is not null;

  if stored_count <> expected_count then
    raise exception 'Codex provenance verification failed: expected % complete rows, found %',
      expected_count,
      stored_count;
  end if;
end
$migration$;

do $constraint$
begin
  if not exists (
    select 1
    from pg_constraint
    where conname = 'codex_documents_provenance_status_allowed'
      and conrelid = 'public.codex_documents'::regclass
  ) then
    alter table public.codex_documents
      add constraint codex_documents_provenance_status_allowed
      check (
        provenance_status is null
        or (
          cardinality(provenance_status) > 0
          and provenance_status <@ array[
            'verified',
            'repository_evidence',
            'concept',
            'unknown'
          ]::text[]
        )
      );
  end if;

  if not exists (
    select 1
    from pg_constraint
    where conname = 'codex_documents_canonical_provenance_complete'
      and conrelid = 'public.codex_documents'::regclass
  ) then
    alter table public.codex_documents
      add constraint codex_documents_canonical_provenance_complete
      check (
        path is null
        or (
          content is not null
          and category is not null
          and provenance_status is not null
          and cardinality(provenance_status) > 0
          and evidence_basis is not null
          and last_reviewed is not null
          and is_read_only is not null
        )
      );
  end if;

  if not exists (
    select 1
    from pg_constraint
    where conname = 'codex_documents_parent_id_fkey'
      and conrelid = 'public.codex_documents'::regclass
  ) then
    alter table public.codex_documents
      add constraint codex_documents_parent_id_fkey
      foreign key (parent_id) references public.codex_documents(id) on delete set null;
  end if;
end
$constraint$;
